Use MSTest's `[DataTestMethod]` with `[DataRow]` to parameterize your tests. Group them by expected outcome:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Validation.Tests;

[TestClass]
public sealed class InputValidatorTests
{
    private InputValidator _validator = null!;

    [TestInitialize]
    public void Setup() => _validator = new InputValidator();

    [DataTestMethod]
    [DataRow("hello-world", DisplayName = "Valid input")]
    [DataRow("abc", DisplayName = "Min length")]
    public void Validate_ValidInput_ReturnsTrue(string input)
    {
        var result = _validator.Validate(input);
        Assert.IsTrue(result.IsValid);
        Assert.IsNull(result.ErrorMessage);
    }

    // DataRow can't use `new string(...)`, so use DynamicData for computed values
    [TestMethod]
    public void Validate_MaxLength_ReturnsTrue()
    {
        var result = _validator.Validate(new string('a', 255));
        Assert.IsTrue(result.IsValid);
    }

    [DataTestMethod]
    [DataRow(null, "Input cannot be empty", DisplayName = "Null")]
    [DataRow("", "Input cannot be empty", DisplayName = "Empty")]
    [DataRow("   ", "Input cannot be empty", DisplayName = "Whitespace")]
    [DataRow("ab", "Input must be at least 3 characters", DisplayName = "Too short")]
    [DataRow("hello<script>", "Input contains invalid characters", DisplayName = "Special chars")]
    public void Validate_InvalidInput_ReturnsFalse(string? input, string expectedError)
    {
        var result = _validator.Validate(input);
        Assert.IsFalse(result.IsValid);
        Assert.AreEqual(expectedError, result.ErrorMessage);
    }

    // For cases needing computed inputs, use DynamicData
    [DynamicData(nameof(TooLongInputs), DynamicDataSourceType.Method)]
    [DataTestMethod]
    public void Validate_TooLong_ReturnsFalse(string input, string expectedError)
    {
        var result = _validator.Validate(input);
        Assert.IsFalse(result.IsValid);
        Assert.AreEqual(expectedError, result.ErrorMessage);
    }

    private static IEnumerable<object[]> TooLongInputs()
    {
        yield return [new string('x', 256), "Input must not exceed 255 characters"];
    }
}
```

**Key points:**

- **`[DataRow]`** — add new cases with one line each; no new method needed
- **`[DynamicData]`** — use for computed values that `DataRow` (compile-time constants only) can't handle
- **`[TestInitialize]`** — eliminates repeated `new InputValidator()` setup
- **`DisplayName`** — keeps test explorer output readable
